[FormControlEventHandler(formControlStr(LedgerTrialBalanceListPage, VerticalDim), FormControlEventType::Lookup)]
public static void VerticalDim_OnLookup(FormControl sender, FormControlEventArgs e)
{
    if(ETGACFParameters::find().EnableUATSmallPoints)
    {

        FormControlCancelableSuperEventArgs ce = e as FormControlCancelableSuperEventArgs;

        SysTableLookup sysTableLookup = SysTableLookup::newParameters(tableNum(DimensionFinancialTag), sender);
        Query query = new Query();
        QueryBuildDataSource qbds;

        ETGACFParameters acfParameters;

        select firstonly acfParameters
                   where acfParameters.DataAreaId == curExt();

        DimensionAttribute dimensionAttribute = DimensionAttribute::findByName(acfParameters.Vertical);

        if (!dimensionAttribute)
        {
            warning("Dimension attribute vertical not found.");
            return;
        }

        RecId fintagcategory = dimensionAttribute.financialTagCategory();

        qbds = query.addDataSource(tableNum(DimensionFinancialTag));
        qbds.addRange(fieldNum(DimensionFinancialTag, FinancialTagCategory)).value(queryValue(fintagcategory));

        sysTableLookup.addLookupField(fieldNum(DimensionFinancialTag, Value));
        sysTableLookup.addLookupField(fieldNum(DimensionFinancialTag, Description));
        sysTableLookup.parmQuery(query);
        sysTableLookup.performFormLookup();

        ce.CancelSuperCall();
    }
}

/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(LedgerTrialBalanceListPage, SubVerticalDim), FormControlEventType::Lookup)]
public static void SubVerticalDim_OnLookup(FormControl sender, FormControlEventArgs e)
{
    if(ETGACFParameters::find().EnableUATSmallPoints)
    {

        Query query;
        SysTableLookup sysTableLookup;
        sysTableLookup = SysTableLookup::newParameters(tableNum(DimAttributeOMBusinessUnit), sender);

        sysTableLookup.addLookupfield(fieldNum(DimAttributeOMBusinessUnit, Value));
        sysTableLookup.addLookupfield(fieldNum(DimAttributeOMBusinessUnit, Name));
        query = new Query();
        query.addDataSource(tableNum(DimAttributeOMBusinessUnit));
        sysTableLookup.parmQuery(query);
        sysTableLookup.performFormLookup();
    }

}

/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(LedgerTrialBalanceListPage, Update), FormControlEventType::Clicked)]
public static void Update_OnClicked(FormControl sender, FormControlEventArgs e)
{

    if(ETGACFParameters::find().EnableUATSmallPoints)
    {

        str                       verticalDimValue,subvertical,dimensionSetName;
        ETGTrailbalanceReport     eTGTrailbalanceReport;

        FormRun             formRun         = sender.formRun();

        FormStringControl verticalDimControl = formRun.design().controlName(formControlStr(LedgerTrialBalanceListPage, VerticalDim)) as FormStringControl;
        FormStringControl subverticalDimControl = formRun.design().controlName(formControlStr(LedgerTrialBalanceListPage, SubVerticalDim)) as FormStringControl;
        FormStringControl DimensionSetNamecontrol = formRun.design().controlName(formControlStr(LedgerTrialBalanceListPage, DimensionSetName)) as FormStringControl;

        delete_from  eTGTrailbalanceReport;

        verticalDimValue = verticalDimControl.valueStr();
        subvertical      = subverticalDimControl.valueStr();
        dimensionSetName = DimensionSetNamecontrol.valueStr();

        eTGTrailbalanceReport.ETGVertical = verticalDimValue;
        eTGTrailbalanceReport.ETGSubVerticalDim = subvertical;
        eTGTrailbalanceReport.DimensionSetName = dimensionSetName;
        eTGTrailbalanceReport.insert();
    }

}
